import React from 'react';
import { Tag as CarbonTag } from '@carbon/react';

const Tag = (props) => {
    const {
        id,
        setProps,
        children,
        className,
        style,
        type,
        size,
        disabled,
        ...otherProps
    } = props;
    return (
        <CarbonTag
            id={id}
            className={className}
            style={style}
            type={type}
            size={size}
            disabled={disabled}
            {...otherProps}
        >
            {children}
        </CarbonTag>
    );
};

Tag.defaultProps = {
    type: 'gray',
    size: 'md',
    disabled: false
};

export default Tag;
